import{_ as t,o as a,c as i,ae as o}from"./chunks/framework.CB71nIlf.js";const d=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"en/1-FAQ/index.md","filePath":"en/1-FAQ/index.md"}'),n={name:"en/1-FAQ/index.md"};function r(s,e,l,c,h,u){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><p>Welcome to the CogniAND platform FAQ page. Here you&#39;ll find answers to the most common questions users encounter.</p><h2 id="quick-navigation" tabindex="-1">Quick Navigation <a class="header-anchor" href="#quick-navigation" aria-label="Permalink to &quot;Quick Navigation&quot;">​</a></h2><ul><li><a href="./1-account.html">Account Related</a> - Registration, login, password reset, etc.</li><li><a href="./2-experiment.html">Experiment Related</a> - Participation, creation, data management, etc.</li><li><a href="./3-technical.html">Technical Issues</a> - Browser compatibility, network, file upload, etc.</li><li><a href="./4-data-privacy.html">Data Privacy</a> - Data collection, privacy protection, informed consent, ethics, etc.</li></ul><h2 id="most-common-questions" tabindex="-1">Most Common Questions <a class="header-anchor" href="#most-common-questions" aria-label="Permalink to &quot;Most Common Questions&quot;">​</a></h2><h3 id="how-to-register-an-account" tabindex="-1">How to register an account? <a class="header-anchor" href="#how-to-register-an-account" aria-label="Permalink to &quot;How to register an account?&quot;">​</a></h3><p>Click the &quot;Login/Register&quot; button in the top right corner, select the &quot;Register&quot; tab, fill in email, password, name and other information, select role (subject/experimenter), submit and the system will send a verification email. Click the verification link in the email to complete registration.</p><p>For detailed steps, see: <a href="/cogniand-manual.github.io/en/3-subject-manual/2-registration-login/2-1-register.html">Subject Manual - Registration</a></p><h3 id="forgot-password" tabindex="-1">Forgot password? <a class="header-anchor" href="#forgot-password" aria-label="Permalink to &quot;Forgot password?&quot;">​</a></h3><p>Click the &quot;Forgot Password&quot; link on the login page, enter your registered email, and the system will send a password reset email. Click the link in the email to set a new password.</p><p>For detailed steps, see: <a href="/cogniand-manual.github.io/en/3-subject-manual/2-registration-login/2-4-password-reset.html">Subject Manual - Password Reset</a></p><h3 id="how-to-participate-in-experiments" tabindex="-1">How to participate in experiments? <a class="header-anchor" href="#how-to-participate-in-experiments" aria-label="Permalink to &quot;How to participate in experiments?&quot;">​</a></h3><p>Log in to your subject account, browse the experiment list on the homepage, click on an experiment you&#39;re interested in to view details, and click the &quot;Apply&quot; button (⚠️ currently a placeholder feature).</p><p>For detailed steps, see: <a href="/cogniand-manual.github.io/en/3-subject-manual/4-participate-experiment/">Subject Manual - Participate in Experiments</a></p><h2 id="need-more-help" tabindex="-1">Need More Help? <a class="header-anchor" href="#need-more-help" aria-label="Permalink to &quot;Need More Help?&quot;">​</a></h2><ul><li>Check <a href="/cogniand-manual.github.io/en/6-troubleshooting/">Troubleshooting</a></li><li>Contact <a href="/cogniand-manual.github.io/en/7-technical-support/1-contact.html">Technical Support</a></li><li>Submit feedback within the platform (after logging in)</li></ul><hr><p><strong>Tip</strong>: This FAQ is continuously updated. Bookmark this page for easy reference.</p>',18)])])}const m=t(n,[["render",r]]);export{d as __pageData,m as default};
